toolArgs.file_text:
.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f8f8;
}

.msg-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.msg-author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1a1a1a;
}

.msg-time {
    font-size: 0.75rem;
    color: #888;
}

.msg-content {
    font-size: 0.9rem;
    color: #333;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: default;
}

.thread-link {
    display: inline-block;
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 4px;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 4px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    font-size: 0.9rem;
    line-height: 1;
}

.action-btn:hover {
    background-color: #f0f0f0;
}

.emoji-picker {
    position: absolute;
    top: -4px;
    right: 8px;
    transform: translateY(-100%);
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 6px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 10;
}

.emoji-pick-btn {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1.2rem;
    padding: 4px;
    border-radius: 4px;
    line-height: 1;
}

.emoji-pick-btn:hover {
    background-color: #f0f0f0;
}

