arguments.file_text:
@using sv_b6277fc20a354bdba7cea423ec86e896.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h5>Channels</h5>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    background: #2c2c3e;
    display: flex;
    flex-direction: column;
    height: 100%;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.sidebar-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

@using sv_b6277fc20a354bdba7cea423ec86e896.Services

<div class="message-list-container">
    @if (HasMore)
    {
        <div class="load-more">
            <button class="btn btn-link btn-sm" @onclick="OnLoadMore">
                ↑ Load older messages
            </button>
        </div>
    }

    <div class="messages">
        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ReplyCount="GetReplyCount(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;
}

.message-list-container {
    flex: 1;
    overflow-y: auto;
    display: flex;
    flex-direction: column;
}

.load-more {
    text-align: center;
    padding: 8px;
    border-bottom: 1px solid #eee;
}

.messages {
    flex: 1;
    padding: 8px 0;
}

@using sv_b6277fc20a354bdba7cea423ec86e896.Services

<div class="message-area">
    <div class="area-header">
        <h4># @ChannelName</h4>
        @if (!string.IsNullOrEmpty(ChannelDescription))
        {
            <p>@ChannelDescription</p>
        }
    </div>

    <MessageList Messages="Messages"
                 ThreadReplyCounts="ThreadReplyCounts"
                 HasMore="HasMore"
                 OnLoadMore="OnLoadMore"
                 OnOpenThread="OnOpenThread"
                 OnReact="OnReact" />

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonText="Send"
                  OnSubmit="OnSend" />
</div>

@code {
    [Parameter] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSend { get; set; }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

.area-header h4 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: #1a1a1a;
}

.area-header p {
    margin: 4px 0 0;
    font-size: 0.8rem;
    color: #666;
}

@using sv_b6277fc20a354bdba7cea423ec86e896.Services

<div class="thread-panel">
    <div class="thread-header">
        <h5>Thread</h5>
        <button class="btn btn-sm btn-outline-secondary close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="msg-header">
                <span class="msg-author">@RootMessage.Author</span>
                <span class="msg-time">@MessageItem.FormatRelativeTime(RootMessage.SentAt)</span>
            </div>
            <div class="msg-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="msg-header">
                        <span class="msg-author">@reply.Author</span>
                        <span class="msg-time">@MessageItem.FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="msg-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonText="Reply"
                      OnSubmit="OnReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
