arguments.file_text:
.chat-page-layout {
    height: 100vh;
    overflow: hidden;
}

#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    box-sizing: border-box;
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

    #blazor-error-ui .dismiss {
        cursor: pointer;
        position: absolute;
        right: 0.75rem;
        top: 0.5rem;
    }

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_b6277fc20a354bdba7cea423ec86e896.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout @(isThreadOpen ? "thread-open" : "")">
    <ChannelSidebar Channels="channels"
                    SelectedChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <MessageArea ChannelName="@selectedChannelName"
                 ChannelDescription="@selectedChannelDesc"
                 Messages="messages"
                 ThreadReplyCounts="threadReplyCounts"
                 HasMore="hasMore"
                 OnLoadMore="LoadMore"
                 OnOpenThread="OpenThread"
                 OnReact="AddReaction"
                 OnSend="SendMessage" />

    @if (isThreadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, int> threadReplyCounts = [];
    private int? selectedChannelId;
    private string selectedChannelName = "";
    private string selectedChannelDesc = "";
    private bool hasMore = true;
    private const int PageSize = 30;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        var channel = channels.FirstOrDefault(c => c.Id == channelId);
        selectedChannelName = channel?.Name ?? "";
        selectedChannelDesc = channel?.Description ?? "";

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        hasMore = messages.Count >= PageSize;
        BuildThreadCounts();
        CloseThread();

        await ChatService.MarkChannelReadAsync(channelId);

        if (channel is not null)
        {
            var idx = channels.IndexOf(channel);
            channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    private async Task LoadMore()
    {
        if (selectedChannelId is null) return;
        var older = await ChatService.GetMessagesAsync(selectedChannelId.Value, messages.Count, PageSize);
        hasMore = older.Count >= PageSize;
        messages.InsertRange(0, older);
        BuildThreadCounts();
    }

    private void BuildThreadCounts()
    {
        threadReplyCounts = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
